with open("atlas/templates/atlas/quiz.html", encoding="utf-8") as f:
    content = f.read()

replacements = [
    ('<div style="font-size: 2rem; margin-bottom: 0.5rem;">🌱</div>', '<div style="margin-bottom:0.5rem;">' + svgs['facil'] + '</div>'),
    ('<div style="font-size: 2rem; margin-bottom: 0.5rem;">🔬</div>', '<div style="margin-bottom:0.5rem;">' + svgs['normal'] + '</div>'),
    ('<div style="font-size: 2rem; margin-bottom: 0.5rem;">💀</div>', '<div style="margin-bottom:0.5rem;">' + svgs['dificil'] + '</div>'),
    ('<div id="resultado-emoji" style="font-size:4rem; margin-bottom:1rem;">🏆</div>', '<div id="resultado-emoji" style="margin-bottom:1rem;">' + svgs['copa'] + '</div>'),
]

count = 0
for old, new in replacements:
    if old in content:
        content = content.replace(old, new, 1)
        count += 1
        print("OK:", old[:40])
    else:
        print("NO ENCONTRADO:", old[:40])

# El emoji de resultado se cambia también en JS
# Dejar el JS como está por ahora - los emojis dinámicos los dejamos para después

with open("atlas/templates/atlas/quiz.html", "w", encoding="utf-8") as f:
    f.write(content)
print(f"DONE: {count} reemplazos")
